import { getLowerCasedCategories } from './get-lower-cased-categories.js';
import { DEFAULT_HONEYCOMB_TILE_COLOR } from '../constants.js';

export const filterCustomCategories = (
  colorScheme: Record<string, string>,
  filter: string[],
) => {
  const lowerCasedCategories = getLowerCasedCategories(colorScheme);
  const chosenCategories: Record<string, string> = {};
  filter.forEach((category) => {
    if (Object.keys(lowerCasedCategories).includes(category.toLowerCase())) {
      chosenCategories[category] = lowerCasedCategories[category.toLowerCase()];
    } else {
      chosenCategories[category] = DEFAULT_HONEYCOMB_TILE_COLOR;
    }
  });

  return chosenCategories;
};
